import React, { useEffect, useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import MainLayout from "../../layouts/MainLayout";
import { PATHS } from "../../constants/paths";
import ApiService from "../../services/ApiService";
import "./PurchaseStaffDashboardPage.css";

const SECTION_COPY = {
  overview: {
    title: "Purchase dashboard",
    subtitle:
      "Theo dõi nhà cung cấp, đơn mua, phiếu nhập kho và lịch sử biến động kho trong cùng một không gian làm việc.",
  },
  suppliers: {
    title: "Danh sách nhà cung cấp",
    subtitle:
      "Chuẩn hoá dữ liệu đối tác cung ứng để phục vụ luồng mua hàng và nhập kho.",
  },
  purchaseOrders: {
    title: "Danh sách đơn mua hàng",
    subtitle:
      "Theo dõi tiến độ xử lý của các đơn mua từ lúc tạo đến khi hoàn tất nhận hàng.",
  },
  goodsReceipts: {
    title: "Danh sách phiếu nhập kho",
    subtitle:
      "Theo dõi các phiếu nhập kho gần đây theo nhà cung cấp, kho đích và thời điểm nhập.",
  },
  inventoryMovements: {
    title: "Inventory movement",
    subtitle:
      "Kiểm tra lịch sử nhập xuất và biến động số lượng để dễ đối soát chứng từ mua hàng.",
  },
};

const ORDER_DETAIL_CONFIG = {
  purchaseOrder: {
    key: "purchaseOrderDetails",
    typeLabel: "Chi tiết đơn mua hàng",
    quantityLabel: "Số lượng đặt",
    quantityKey: "orderedQuantity",
    priceLabel: "Giá dự kiến",
    priceKey: "unitPriceEstimated",
    totalLabel: "Thành tiền dự kiến",
    totalKey: "lineTotalEstimated",
    loader: (identifier) => ApiService.getPurchaseOrderDetails(identifier),
  },
  stockInward: {
    key: "stockInwardDetails",
    typeLabel: "Chi tiết phiếu nhập kho",
    quantityLabel: "Số lượng nhận",
    quantityKey: "quantityReceived",
    priceLabel: "Giá mua thực tế",
    priceKey: "unitPriceNegotiated",
    fallbackPriceKey: "unitPurchasePrice",
    totalLabel: "Giá trị dòng",
    totalKey: "lineValue",
    loader: (identifier) => ApiService.getStockInwardDetails(identifier),
  },
};

const PAGE_SIZE = 10;

const STATUS_LABELS = {
  APPROVED: "Đã duyệt",
  AVAILABLE: "Khả dụng",
  CANCELLED: "Đã hủy",
  COMPLETED: "Hoàn tất",
  CREATED: "Mới tạo",
  DELIVERED: "Đã giao",
  INBOUND: "Nhập kho",
  LOW_STOCK: "Sắp hết",
  ORDERED: "Đã đặt hàng",
  OUTBOUND: "Xuất kho",
  OUT_OF_STOCK: "Hết hàng",
  PARTIALLY_RECEIVED: "Nhận một phần",
  PENDING: "Chờ xử lý",
  PROCESSING: "Đang xử lý",
  RECEIVED: "Đã nhận",
  REJECTED: "Từ chối",
  STOCK_IN: "Nhập kho",
  STOCK_OUT: "Xuất kho",
  TRANSFER: "Điều chuyển",
  UPDATED: "Đã cập nhật",
};

function formatStatus(value) {
  const normalizedValue = String(value || "").trim().toUpperCase();

  if (!normalizedValue) {
    return "Chưa cập nhật";
  }

  if (STATUS_LABELS[normalizedValue]) {
    return STATUS_LABELS[normalizedValue];
  }

  return normalizedValue
    .toLowerCase()
    .split("_")
    .map((segment) => segment.charAt(0).toUpperCase() + segment.slice(1))
    .join(" ");
}

function formatDate(value) {
  if (!value) {
    return "Chưa cập nhật";
  }

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return "Chưa cập nhật";
  }

  return date.toLocaleString("vi-VN");
}

function formatCompactNumber(value) {
  return new Intl.NumberFormat("vi-VN").format(Number(value || 0));
}

function formatCurrency(value) {
  const amount = Number(value);

  if (!Number.isFinite(amount)) {
    return "N/A";
  }

  return new Intl.NumberFormat("vi-VN", {
    style: "currency",
    currency: "VND",
    maximumFractionDigits: 0,
  }).format(amount);
}

function formatSignedQuantity(value) {
  const amount = Number(value || 0);

  if (amount > 0) {
    return `+${amount}`;
  }

  return String(amount);
}

function getStatusTone(status) {
  const normalizedValue = String(status || "").toUpperCase();

  if (
    [
      "REJECTED",
      "CANCELLED",
      "OUT_OF_STOCK",
      "STOCK_OUT",
      "OUTBOUND",
    ].includes(normalizedValue)
  ) {
    return "danger";
  }

  if (
    [
      "PENDING",
      "PROCESSING",
      "ORDERED",
      "PARTIALLY_RECEIVED",
      "LOW_STOCK",
    ].includes(normalizedValue)
  ) {
    return "warning";
  }

  if (
    [
      "APPROVED",
      "RECEIVED",
      "DELIVERED",
      "AVAILABLE",
      "STOCK_IN",
      "INBOUND",
      "COMPLETED",
    ].includes(normalizedValue)
  ) {
    return "success";
  }

  return "neutral";
}

function normalizeCollection(payload, collectionKey) {
  if (Array.isArray(payload?.[collectionKey])) {
    return payload[collectionKey];
  }

  if (Array.isArray(payload?.data)) {
    return payload.data;
  }

  return [];
}

function matchesSearch(searchTerm, fields) {
  const normalizedSearch = String(searchTerm || "").trim().toLowerCase();

  if (!normalizedSearch) {
    return true;
  }

  return fields.some((field) => String(field || "").toLowerCase().includes(normalizedSearch));
}

function clampPage(page, totalItems) {
  const totalPages = Math.max(1, Math.ceil(totalItems / PAGE_SIZE));
  return Math.min(Math.max(page, 1), totalPages);
}

function PurchaseEmptyState({ title, description }) {
  return (
    <div className="purchase-empty-state">
      <strong>{title}</strong>
      <p>{description}</p>
    </div>
  );
}

function Pagination({ currentPage, totalItems, onChange }) {
  const totalPages = Math.max(1, Math.ceil(totalItems / PAGE_SIZE));

  if (totalPages <= 1) {
    return null;
  }

  return (
    <div className="purchase-pagination" aria-label="Pagination">
      <button
        type="button"
        className="purchase-pagination-button"
        disabled={currentPage === 1}
        onClick={() => onChange(currentPage - 1)}
      >
        «
      </button>

      {Array.from({ length: totalPages }, (_, index) => {
        const page = index + 1;

        return (
          <button
            key={page}
            type="button"
            className={
              page === currentPage
                ? "purchase-pagination-button active"
                : "purchase-pagination-button"
            }
            onClick={() => onChange(page)}
          >
            {page}
          </button>
        );
      })}

      <button
        type="button"
        className="purchase-pagination-button"
        disabled={currentPage === totalPages}
        onClick={() => onChange(currentPage + 1)}
      >
        »
      </button>
    </div>
  );
}

const PurchaseStaffDashboardPage = ({ activeSection = "overview" }) => {
  const navigate = useNavigate();
  const timeoutRef = useRef(null);
  const [message, setMessage] = useState("");
  const [isLoading, setIsLoading] = useState(true);
  const [supplierSearchTerm, setSupplierSearchTerm] = useState("");
  const [purchaseOrderSearchTerm, setPurchaseOrderSearchTerm] = useState("");
  const [goodsReceiptSearchTerm, setGoodsReceiptSearchTerm] = useState("");
  const [movementSearchTerm, setMovementSearchTerm] = useState("");
  const [pages, setPages] = useState({
    suppliers: 1,
    purchaseOrders: 1,
    goodsReceipts: 1,
    inventoryMovements: 1,
  });
  const [detailDialog, setDetailDialog] = useState({
    isOpen: false,
    isLoading: false,
    title: "",
    subtitle: "",
    status: "",
    error: "",
    items: [],
    config: null,
  });
  const [dashboardData, setDashboardData] = useState({
    suppliers: [],
    purchaseOrders: [],
    goodsReceipts: [],
    inventoryMovements: [],
  });

  useEffect(() => {
    async function loadDashboardData() {
      setIsLoading(true);

      try {
        const [
          supplierResult,
          purchaseOrderResult,
          goodsReceiptResult,
          movementResult,
        ] = await Promise.allSettled([
          ApiService.getAllSuppliers(),
          ApiService.getAllPurchaseOrders(),
          ApiService.getAllStockInwards(),
          ApiService.getInventoryMovements(),
        ]);

        const nextData = {
          suppliers:
            supplierResult.status === "fulfilled"
              ? supplierResult.value?.suppliers || []
              : [],
          purchaseOrders:
            purchaseOrderResult.status === "fulfilled"
              ? purchaseOrderResult.value?.purchaseOrders || []
              : [],
          goodsReceipts:
            goodsReceiptResult.status === "fulfilled"
              ? normalizeCollection(goodsReceiptResult.value, "stockInwards")
              : [],
          inventoryMovements:
            movementResult.status === "fulfilled"
              ? normalizeCollection(movementResult.value, "inventoryMovements")
              : [],
        };

        setDashboardData(nextData);

        const errors = [
          supplierResult,
          purchaseOrderResult,
          goodsReceiptResult,
          movementResult,
        ]
          .filter((result) => result.status === "rejected")
          .map((result) => result.reason?.response?.data?.message || "Unable to load data.");

        if (errors.length) {
          showMessage(errors[0]);
        }
      } finally {
        setIsLoading(false);
      }
    }

    loadDashboardData();

    return () => {
      if (timeoutRef.current) {
        window.clearTimeout(timeoutRef.current);
      }
    };
  }, []);

  function showMessage(nextMessage) {
    setMessage(nextMessage);

    if (timeoutRef.current) {
      window.clearTimeout(timeoutRef.current);
    }

    timeoutRef.current = window.setTimeout(() => {
      setMessage("");
    }, 4000);
  }

  function updatePage(section, nextPage) {
    setPages((currentValue) => ({
      ...currentValue,
      [section]: nextPage,
    }));
  }

  function closeDetailDialog() {
    setDetailDialog({
      isOpen: false,
      isLoading: false,
      title: "",
      subtitle: "",
      status: "",
      error: "",
      items: [],
      config: null,
    });
  }

  async function openOrderDetails(kind, row) {
    const config = ORDER_DETAIL_CONFIG[kind];

    if (!config) {
      return;
    }

    setDetailDialog({
      isOpen: true,
      isLoading: true,
      title: row.code,
      subtitle: `${row.partner} | ${row.warehouse}`,
      status: row.status,
      error: "",
      items: [],
      config,
    });

    try {
      const response = await config.loader(row.id);

      setDetailDialog((currentValue) => ({
        ...currentValue,
        isLoading: false,
        items: normalizeCollection(response, config.key),
      }));
    } catch (error) {
      setDetailDialog((currentValue) => ({
        ...currentValue,
        isLoading: false,
        error:
          error.response?.data?.message ||
          `Không thể tải ${config.typeLabel.toLowerCase()}.`,
      }));
    }
  }

  const {
    suppliers,
    purchaseOrders,
    goodsReceipts,
    inventoryMovements,
  } = dashboardData;

  const supplierRows = useMemo(
    () =>
      suppliers.map((supplier) => ({
        id: supplier.id,
        name: supplier.name || "Chưa có tên",
        contactInfo: supplier.contactInfo || "Chưa cập nhật",
        address: supplier.address || "Chưa cập nhật",
      })),
    [suppliers]
  );

  const purchaseOrderRows = useMemo(
    () =>
      purchaseOrders
        .map((order) => ({
          id: order.id,
          code: order.orderCode || `PO-${order.id}`,
          partner: order.supplierName || "Chưa gán nhà cung cấp",
          warehouse: order.warehouseName || "Chưa gán kho",
          totalItems: order.totalItems || 0,
          status: formatStatus(order.status),
          rawStatus: order.status,
          updatedAt: order.updatedAt || order.createdAt || order.orderDate,
        }))
        .sort((left, right) => new Date(right.updatedAt || 0) - new Date(left.updatedAt || 0)),
    [purchaseOrders]
  );

  const goodsReceiptRows = useMemo(
    () =>
      goodsReceipts
        .map((receipt) => ({
          id: receipt.stockInwardId,
          code: receipt.inwardCode || `INW-${receipt.stockInwardId}`,
          partner: receipt.supplierName || "Chưa gán nhà cung cấp",
          warehouse: receipt.warehouseName || "Chưa gán kho",
          totalItems: receipt.totalReceivedQuantity || receipt.totalItems || 0,
          status: formatStatus(receipt.status),
          rawStatus: receipt.status,
          updatedAt: receipt.createdAt || receipt.inwardDate,
        }))
        .sort((left, right) => new Date(right.updatedAt || 0) - new Date(left.updatedAt || 0)),
    [goodsReceipts]
  );

  const movementRows = useMemo(
    () =>
      inventoryMovements
        .map((movement) => ({
          id: movement.movementId,
          createdAt: movement.createdAt,
          product: movement.productName || "Chưa có sản phẩm",
          productSku: movement.productSku || "N/A",
          warehouse: movement.warehouseName || "Chưa gán kho",
          movementType: formatStatus(movement.movementType),
          rawMovementType: movement.movementType,
          reference: movement.referenceCode || movement.referenceId || "Manual",
          referenceType: formatStatus(movement.referenceType),
          actor: movement.actorUserName || "System",
          before: movement.quantityBefore || 0,
          delta: Number(movement.quantityDelta || 0),
          after: movement.quantityAfter || 0,
        }))
        .sort((left, right) => new Date(right.createdAt || 0) - new Date(left.createdAt || 0)),
    [inventoryMovements]
  );

  const filteredSuppliers = useMemo(
    () =>
      supplierRows.filter((supplier) =>
        matchesSearch(supplierSearchTerm, [
          supplier.name,
          supplier.contactInfo,
          supplier.address,
        ])
      ),
    [supplierRows, supplierSearchTerm]
  );

  const filteredPurchaseOrderRows = useMemo(
    () =>
      purchaseOrderRows.filter((row) =>
        matchesSearch(purchaseOrderSearchTerm, [
          row.code,
          row.partner,
          row.warehouse,
          row.status,
        ])
      ),
    [purchaseOrderRows, purchaseOrderSearchTerm]
  );

  const filteredGoodsReceiptRows = useMemo(
    () =>
      goodsReceiptRows.filter((row) =>
        matchesSearch(goodsReceiptSearchTerm, [
          row.code,
          row.partner,
          row.warehouse,
          row.status,
        ])
      ),
    [goodsReceiptRows, goodsReceiptSearchTerm]
  );

  const filteredInventoryMovements = useMemo(
    () =>
      movementRows.filter((row) =>
        matchesSearch(movementSearchTerm, [
          row.product,
          row.productSku,
          row.warehouse,
          row.movementType,
          row.reference,
          row.referenceType,
          row.actor,
        ])
      ),
    [movementRows, movementSearchTerm]
  );

  const overviewCards = useMemo(
    () => [
      {
        label: "Nhà cung cấp",
        value: suppliers.length,
        helper: "Đối tác đang theo dõi",
      },
      {
        label: "Đơn mua hàng",
        value: purchaseOrders.length,
        helper: "Chứng từ mua hàng hiện có",
      },
      {
        label: "Phiếu nhập kho",
        value: goodsReceipts.length,
        helper: "Lần nhập kho đã ghi nhận",
      },
      {
        label: "Inventory movement",
        value: inventoryMovements.length,
        helper: "Biến động kho gần đây",
      },
    ],
    [
      goodsReceipts.length,
      inventoryMovements.length,
      purchaseOrders.length,
      suppliers.length,
    ]
  );

  const pendingPurchaseCount = useMemo(
    () =>
      purchaseOrders.filter((order) =>
        ["PENDING", "ORDERED", "PARTIALLY_RECEIVED", "PROCESSING"].includes(
          String(order.status || "").toUpperCase()
        )
      ).length,
    [purchaseOrders]
  );

  const recentSuppliers = filteredSuppliers.slice(0, 5);
  const recentPurchaseOrders = filteredPurchaseOrderRows.slice(0, 5);
  const recentGoodsReceipts = filteredGoodsReceiptRows.slice(0, 5);

  const activeCopy = SECTION_COPY[activeSection] || SECTION_COPY.overview;

  function paginate(rows, section) {
    const currentPage = clampPage(pages[section], rows.length);
    const startIndex = (currentPage - 1) * PAGE_SIZE;

    return {
      currentPage,
      rows: rows.slice(startIndex, startIndex + PAGE_SIZE),
      startIndex,
    };
  }

  function renderOverview() {
    return (
      <>
        <section className="purchase-stats-grid">
          {overviewCards.map((card) => (
            <article key={card.label} className="purchase-stat-card">
              <span>{card.label}</span>
              <strong>{formatCompactNumber(card.value)}</strong>
              <p>{card.helper}</p>
            </article>
          ))}
        </section>

        <section className="purchase-overview-grid">
          <article className="purchase-panel">
            <div className="purchase-panel-heading">
              <div>
                <p className="purchase-panel-label">Điểm cần chú ý</p>
                <h2>Tiến độ mua hàng</h2>
              </div>
            </div>

            <div className="purchase-kpi-strip">
              <div>
                <span>Chờ xử lý</span>
                <strong>{formatCompactNumber(pendingPurchaseCount)}</strong>
              </div>
              <div>
                <span>Phiếu nhập</span>
                <strong>{formatCompactNumber(goodsReceipts.length)}</strong>
              </div>
              <div>
                <span>Biến động kho</span>
                <strong>{formatCompactNumber(inventoryMovements.length)}</strong>
              </div>
            </div>

            <div className="purchase-quick-grid">
              <button
                type="button"
                className="purchase-quick-card"
                onClick={() => navigate(PATHS.dashboardSuppliers)}
              >
                <strong>Nhà cung cấp</strong>
                <span>Tra cứu và rà soát dữ liệu đối tác.</span>
              </button>
              <button
                type="button"
                className="purchase-quick-card"
                onClick={() => navigate(PATHS.dashboardPurchaseOrders)}
              >
                <strong>Đơn mua hàng</strong>
                <span>Theo dõi trạng thái xử lý chứng từ mua.</span>
              </button>
              <button
                type="button"
                className="purchase-quick-card"
                onClick={() => navigate(PATHS.dashboardGoodsReceipts)}
              >
                <strong>Phiếu nhập kho</strong>
                <span>Kiểm tra chứng từ nhập và số lượng nhận.</span>
              </button>
              <button
                type="button"
                className="purchase-quick-card"
                onClick={() => navigate(PATHS.dashboardInventoryMovements)}
              >
                <strong>Inventory movement</strong>
                <span>Đối soát lịch sử tăng giảm tồn kho.</span>
              </button>
            </div>
          </article>

          <article className="purchase-panel">
            <div className="purchase-panel-heading">
              <div>
                <p className="purchase-panel-label">Đối tác mới nhất</p>
                <h2>Nhà cung cấp gần đây</h2>
              </div>
              <button
                type="button"
                className="purchase-link-button"
                onClick={() => navigate(PATHS.dashboardSuppliers)}
              >
                Xem tất cả
              </button>
            </div>

            {recentSuppliers.length ? (
              <div className="purchase-list">
                {recentSuppliers.map((supplier) => (
                  <div key={supplier.id} className="purchase-list-row">
                    <div>
                      <strong>{supplier.name}</strong>
                      <p>{supplier.contactInfo}</p>
                    </div>
                    <span>{supplier.address}</span>
                  </div>
                ))}
              </div>
            ) : (
              <PurchaseEmptyState
                title="Chưa có nhà cung cấp"
                description="Danh sách nhà cung cấp sẽ hiển thị tại đây khi có dữ liệu."
              />
            )}
          </article>
        </section>

        <section className="purchase-overview-grid purchase-overview-grid-tight">
          <article className="purchase-panel">
            <div className="purchase-panel-heading">
              <div>
                <p className="purchase-panel-label">Đơn mua mới</p>
                <h2>Đơn mua hàng gần đây</h2>
              </div>
            </div>

            {recentPurchaseOrders.length ? (
              <div className="purchase-list">
                {recentPurchaseOrders.map((row) => (
                  <button
                    key={row.id}
                    type="button"
                    className="purchase-list-button"
                    onClick={() => openOrderDetails("purchaseOrder", row)}
                  >
                    <div>
                      <strong>{row.code}</strong>
                      <p>{row.partner}</p>
                    </div>
                    <div className="purchase-list-meta">
                      <span className={`purchase-badge tone-${getStatusTone(row.rawStatus)}`}>
                        {row.status}
                      </span>
                      <small>{formatDate(row.updatedAt)}</small>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <PurchaseEmptyState
                title="Chưa có đơn mua hàng"
                description="Các đơn mua gần đây sẽ hiển thị ở khu vực này."
              />
            )}
          </article>

          <article className="purchase-panel">
            <div className="purchase-panel-heading">
              <div>
                <p className="purchase-panel-label">Nhập kho gần đây</p>
                <h2>Phiếu nhập mới nhất</h2>
              </div>
            </div>

            {recentGoodsReceipts.length ? (
              <div className="purchase-list">
                {recentGoodsReceipts.map((row) => (
                  <button
                    key={row.id}
                    type="button"
                    className="purchase-list-button"
                    onClick={() => openOrderDetails("stockInward", row)}
                  >
                    <div>
                      <strong>{row.code}</strong>
                      <p>{row.partner}</p>
                    </div>
                    <div className="purchase-list-meta">
                      <span className={`purchase-badge tone-${getStatusTone(row.rawStatus)}`}>
                        {row.status}
                      </span>
                      <small>{formatDate(row.updatedAt)}</small>
                    </div>
                  </button>
                ))}
              </div>
            ) : (
              <PurchaseEmptyState
                title="Chưa có phiếu nhập kho"
                description="Phiếu nhập mới nhất sẽ hiển thị ở khu vực này."
              />
            )}
          </article>
        </section>
      </>
    );
  }

  function renderSuppliers() {
    const { currentPage, rows, startIndex } = paginate(filteredSuppliers, "suppliers");

    return (
      <section className="purchase-section-card">
        <div className="purchase-toolbar">
          <input
            className="purchase-search-input"
            value={supplierSearchTerm}
            onChange={(event) => setSupplierSearchTerm(event.target.value)}
            placeholder="Tìm theo tên nhà cung cấp, liên hệ hoặc địa chỉ"
          />
        </div>

        {rows.length ? (
          <>
            <div className="purchase-table-shell">
              <table className="purchase-table">
                <thead>
                  <tr>
                    <th>STT</th>
                    <th>Tên nhà cung cấp</th>
                    <th>Liên hệ</th>
                    <th>Địa chỉ</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((supplier, index) => (
                    <tr key={supplier.id}>
                      <td>{startIndex + index + 1}</td>
                      <td>
                        <strong>{supplier.name}</strong>
                      </td>
                      <td>{supplier.contactInfo}</td>
                      <td>{supplier.address}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <Pagination
              currentPage={currentPage}
              totalItems={filteredSuppliers.length}
              onChange={(page) => updatePage("suppliers", page)}
            />
          </>
        ) : (
          <PurchaseEmptyState
            title="Không tìm thấy nhà cung cấp"
            description="Thử lại với từ khoá khác để lọc danh sách nhà cung cấp."
          />
        )}
      </section>
    );
  }

  function renderPurchaseOrders() {
    const { currentPage, rows, startIndex } = paginate(
      filteredPurchaseOrderRows,
      "purchaseOrders"
    );

    return (
      <section className="purchase-section-card">
        <div className="purchase-toolbar">
          <input
            className="purchase-search-input"
            value={purchaseOrderSearchTerm}
            onChange={(event) => setPurchaseOrderSearchTerm(event.target.value)}
            placeholder="Tìm theo mã phiếu, nhà cung cấp, kho hoặc trạng thái"
          />
        </div>

        {rows.length ? (
          <>
            <div className="purchase-table-shell">
              <table className="purchase-table">
                <thead>
                  <tr>
                    <th>STT</th>
                    <th>Mã phiếu</th>
                    <th>Nhà cung cấp</th>
                    <th>Kho</th>
                    <th>Số mặt hàng</th>
                    <th>Trạng thái</th>
                    <th>Cập nhật</th>
                    <th>Hành động</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((row, index) => (
                    <tr key={row.id}>
                      <td>{startIndex + index + 1}</td>
                      <td>
                        <strong>{row.code}</strong>
                      </td>
                      <td>{row.partner}</td>
                      <td>{row.warehouse}</td>
                      <td>{row.totalItems}</td>
                      <td>
                        <span className={`purchase-badge tone-${getStatusTone(row.rawStatus)}`}>
                          {row.status}
                        </span>
                      </td>
                      <td>{formatDate(row.updatedAt)}</td>
                      <td>
                        <button
                          type="button"
                          className="purchase-row-action"
                          onClick={() => openOrderDetails("purchaseOrder", row)}
                        >
                          Chi tiết
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <Pagination
              currentPage={currentPage}
              totalItems={filteredPurchaseOrderRows.length}
              onChange={(page) => updatePage("purchaseOrders", page)}
            />
          </>
        ) : (
          <PurchaseEmptyState
            title="Không có đơn mua phù hợp"
            description="Không có đơn mua hàng nào khớp với bộ lọc hiện tại."
          />
        )}
      </section>
    );
  }

  function renderGoodsReceipts() {
    const { currentPage, rows, startIndex } = paginate(
      filteredGoodsReceiptRows,
      "goodsReceipts"
    );

    return (
      <section className="purchase-section-card">
        <div className="purchase-toolbar">
          <input
            className="purchase-search-input"
            value={goodsReceiptSearchTerm}
            onChange={(event) => setGoodsReceiptSearchTerm(event.target.value)}
            placeholder="Tìm theo mã nhập, nhà cung cấp, kho hoặc trạng thái"
          />
        </div>

        {rows.length ? (
          <>
            <div className="purchase-table-shell">
              <table className="purchase-table">
                <thead>
                  <tr>
                    <th>STT</th>
                    <th>Mã nhập</th>
                    <th>Nhà cung cấp</th>
                    <th>Kho</th>
                    <th>Số lượng nhận</th>
                    <th>Trạng thái</th>
                    <th>Ngày nhập</th>
                    <th>Hành động</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((row, index) => (
                    <tr key={row.id}>
                      <td>{startIndex + index + 1}</td>
                      <td>
                        <strong>{row.code}</strong>
                      </td>
                      <td>{row.partner}</td>
                      <td>{row.warehouse}</td>
                      <td>{row.totalItems}</td>
                      <td>
                        <span className={`purchase-badge tone-${getStatusTone(row.rawStatus)}`}>
                          {row.status}
                        </span>
                      </td>
                      <td>{formatDate(row.updatedAt)}</td>
                      <td>
                        <button
                          type="button"
                          className="purchase-row-action"
                          onClick={() => openOrderDetails("stockInward", row)}
                        >
                          Chi tiết
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <Pagination
              currentPage={currentPage}
              totalItems={filteredGoodsReceiptRows.length}
              onChange={(page) => updatePage("goodsReceipts", page)}
            />
          </>
        ) : (
          <PurchaseEmptyState
            title="Không có phiếu nhập phù hợp"
            description="Danh sách phiếu nhập kho sẽ hiện ra khi có chứng từ phù hợp bộ lọc."
          />
        )}
      </section>
    );
  }

  function renderInventoryMovements() {
    const { currentPage, rows, startIndex } = paginate(
      filteredInventoryMovements,
      "inventoryMovements"
    );

    return (
      <section className="purchase-section-card">
        <div className="purchase-toolbar">
          <input
            className="purchase-search-input"
            value={movementSearchTerm}
            onChange={(event) => setMovementSearchTerm(event.target.value)}
            placeholder="Tìm theo sản phẩm, kho, loại biến động, người thao tác hoặc chứng từ"
          />
        </div>

        {rows.length ? (
          <>
            <div className="purchase-table-shell">
              <table className="purchase-table">
                <thead>
                  <tr>
                    <th>STT</th>
                    <th>Thời gian</th>
                    <th>Sản phẩm</th>
                    <th>Kho</th>
                    <th>Biến động</th>
                    <th>Chứng từ</th>
                    <th>Người thao tác</th>
                    <th>Trước</th>
                    <th>Delta</th>
                    <th>Sau</th>
                  </tr>
                </thead>
                <tbody>
                  {rows.map((row, index) => (
                    <tr key={row.id}>
                      <td>{startIndex + index + 1}</td>
                      <td>{formatDate(row.createdAt)}</td>
                      <td>
                        <strong>{row.product}</strong>
                        <span>{row.productSku}</span>
                      </td>
                      <td>{row.warehouse}</td>
                      <td>
                        <span
                          className={`purchase-badge tone-${getStatusTone(
                            row.rawMovementType
                          )}`}
                        >
                          {row.movementType}
                        </span>
                      </td>
                      <td>
                        <strong>{row.reference}</strong>
                        <span>{row.referenceType}</span>
                      </td>
                      <td>{row.actor}</td>
                      <td>{row.before}</td>
                      <td className={row.delta >= 0 ? "movement-up" : "movement-down"}>
                        {formatSignedQuantity(row.delta)}
                      </td>
                      <td>{row.after}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <Pagination
              currentPage={currentPage}
              totalItems={filteredInventoryMovements.length}
              onChange={(page) => updatePage("inventoryMovements", page)}
            />
          </>
        ) : (
          <PurchaseEmptyState
            title="Không có lịch sử biến động"
            description="Inventory movement sẽ hiển thị tại đây sau khi có nhập hoặc xuất kho."
          />
        )}
      </section>
    );
  }

  function renderActiveSection() {
    if (activeSection === "suppliers") {
      return renderSuppliers();
    }

    if (activeSection === "purchaseOrders") {
      return renderPurchaseOrders();
    }

    if (activeSection === "goodsReceipts") {
      return renderGoodsReceipts();
    }

    if (activeSection === "inventoryMovements") {
      return renderInventoryMovements();
    }

    return renderOverview();
  }

  return (
    <MainLayout>
      {message ? <div className="message">{message}</div> : null}

      <div className="purchase-dashboard-page">
        <section className="purchase-page-shell">
          <div className="purchase-page-header">
            <div className="purchase-page-title">
              <span className="purchase-page-kicker">Purchase dashboard</span>
              <h1>{activeCopy.title}</h1>
              <p>{activeCopy.subtitle}</p>
            </div>

            <div className="purchase-page-summary-card">
              <span>Tổng quan nhanh</span>
              <strong>{formatCompactNumber(pendingPurchaseCount)}</strong>
              <p>đơn mua hàng đang cần theo dõi hoặc tiếp tục xử lý.</p>
            </div>
          </div>

          {isLoading ? (
            <section className="purchase-loading-grid" aria-label="Loading purchase dashboard">
              <div className="purchase-loading-card" />
              <div className="purchase-loading-card" />
              <div className="purchase-loading-card" />
            </section>
          ) : (
            renderActiveSection()
          )}
        </section>
      </div>

      {detailDialog.isOpen ? (
        <div
          className="purchase-dialog-backdrop"
          role="presentation"
          onClick={closeDetailDialog}
        >
          <section
            className="purchase-dialog"
            role="dialog"
            aria-modal="true"
            aria-labelledby="purchase-detail-title"
            onClick={(event) => event.stopPropagation()}
          >
            <div className="purchase-panel-heading purchase-dialog-heading">
              <div>
                <p className="purchase-panel-label">
                  {detailDialog.config?.typeLabel || "Chi tiết"}
                </p>
                <h2 id="purchase-detail-title">{detailDialog.title}</h2>
                <p className="purchase-dialog-subtitle">{detailDialog.subtitle}</p>
              </div>

              <div className="purchase-dialog-actions">
                {detailDialog.status ? (
                  <span className="purchase-badge tone-neutral">{detailDialog.status}</span>
                ) : null}
                <button
                  type="button"
                  className="purchase-link-button"
                  onClick={closeDetailDialog}
                >
                  Đóng
                </button>
              </div>
            </div>

            {detailDialog.isLoading ? (
              <PurchaseEmptyState
                title="Đang tải chi tiết"
                description="Hệ thống đang lấy danh sách dòng hàng mới nhất."
              />
            ) : detailDialog.error ? (
              <PurchaseEmptyState
                title="Không thể tải chi tiết"
                description={detailDialog.error}
              />
            ) : detailDialog.items.length ? (
              <div className="purchase-table-shell">
                <table className="purchase-table">
                  <thead>
                    <tr>
                      <th>STT</th>
                      <th>Sản phẩm</th>
                      <th>{detailDialog.config?.quantityLabel}</th>
                      <th>{detailDialog.config?.priceLabel}</th>
                      <th>{detailDialog.config?.totalLabel}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {detailDialog.items.map((item, index) => (
                      <tr key={`${detailDialog.title}-${index}`}>
                        <td>{index + 1}</td>
                        <td>
                          <strong>{item.productName || item.productSku || "N/A"}</strong>
                          <span>{item.productSku || "Không có SKU"}</span>
                        </td>
                        <td>{item[detailDialog.config?.quantityKey] || 0}</td>
                        <td>
                          {formatCurrency(
                            item[detailDialog.config?.priceKey] ??
                              item[detailDialog.config?.fallbackPriceKey]
                          )}
                        </td>
                        <td>{formatCurrency(item[detailDialog.config?.totalKey])}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            ) : (
              <PurchaseEmptyState
                title="Không có dòng dữ liệu"
                description="Chứng từ này hiện chưa có dòng sản phẩm để hiển thị."
              />
            )}
          </section>
        </div>
      ) : null}
    </MainLayout>
  );
};

export default PurchaseStaffDashboardPage;
